@import 'tailwindcss';
@import 'tw-animate-css';

@config '../../../tailwind.config.ts';

@custom-variant dark (&:is(.dark *));

/*
 * JobAutoAgent Color Scheme
 * ────────────────────
 * Indigo primary — professional, trustworthy, modern
 * Slate neutrals — clean, cool-toned grays
 * Semantic status colors — success (emerald), warning (amber), info (sky)
 *
 * Built on OKLCH for perceptual uniformity across light/dark modes.
 * Theme tokens are defined in tailwind.config.ts at the project root.
 */

/* ───────────────────────────────────────────────
 * Light Mode
 * Slate neutrals · Indigo-600 primary · Semantic status
 * ─────────────────────────────────────────────── */
:root {
  --radius: 0.625rem;

  /* Surfaces */
  --background: oklch(1 0 0);
  --foreground: oklch(0.129 0.042 264.695);
  --card: oklch(1 0 0);
  --card-foreground: oklch(0.129 0.042 264.695);
  --popover: oklch(1 0 0);
  --popover-foreground: oklch(0.129 0.042 264.695);

  /* Brand — Indigo */
  --primary: oklch(0.511 0.262 276.966);
  --primary-foreground: oklch(0.962 0.018 272.314);
  --secondary: oklch(0.968 0.007 247.896);
  --secondary-foreground: oklch(0.208 0.042 265.755);

  /* Muted — Slate */
  --muted: oklch(0.968 0.007 247.896);
  --muted-foreground: oklch(0.554 0.046 257.417);

  /* Accent — Subtle indigo-tinted gray */
  --accent: oklch(0.968 0.007 247.896);
  --accent-foreground: oklch(0.208 0.042 265.755);

  /* Destructive — Red */
  --destructive: oklch(0.577 0.245 27.325);
  --destructive-foreground: oklch(0.985 0 0);

  /* Success — Emerald (applied) */
  --success: oklch(0.596 0.145 163.225);
  --success-foreground: oklch(0.985 0 0);

  /* Warning — Amber (needs review) */
  --warning: oklch(0.769 0.188 70.08);
  --warning-foreground: oklch(0.208 0.042 265.755);

  /* Info — Sky (in-progress, informational) */
  --info: oklch(0.685 0.169 237.323);
  --info-foreground: oklch(0.985 0 0);

  /* Interactive */
  --border: oklch(0.929 0.013 255.508);
  --input: oklch(0.929 0.013 255.508);
  --ring: oklch(0.585 0.233 277.117);

  /* Charts — Harmonious multi-hue palette */
  --chart-1: oklch(0.585 0.233 277.117);
  --chart-2: oklch(0.696 0.17 162.48);
  --chart-3: oklch(0.769 0.188 70.08);
  --chart-4: oklch(0.645 0.246 16.439);
  --chart-5: oklch(0.627 0.265 303.9);

  /* Sidebar */
  --sidebar: oklch(0.984 0.003 247.858);
  --sidebar-foreground: oklch(0.129 0.042 264.695);
  --sidebar-primary: oklch(0.511 0.262 276.966);
  --sidebar-primary-foreground: oklch(0.962 0.018 272.314);
  --sidebar-accent: oklch(0.968 0.007 247.896);
  --sidebar-accent-foreground: oklch(0.208 0.042 265.755);
  --sidebar-border: oklch(0.929 0.013 255.508);
  --sidebar-ring: oklch(0.585 0.233 277.117);
}

/* ───────────────────────────────────────────────
 * Dark Mode
 * Deep slate bg · Indigo-400 primary · Elevated cards
 * ─────────────────────────────────────────────── */
.dark {
  /* Surfaces */
  --background: oklch(0.129 0.042 264.695);
  --foreground: oklch(0.984 0.003 247.858);
  --card: oklch(0.208 0.042 265.755);
  --card-foreground: oklch(0.984 0.003 247.858);
  --popover: oklch(0.208 0.042 265.755);
  --popover-foreground: oklch(0.984 0.003 247.858);

  /* Brand — Lighter indigo for dark backgrounds */
  --primary: oklch(0.673 0.182 276.935);
  --primary-foreground: oklch(0.257 0.09 281.288);
  --secondary: oklch(0.279 0.041 260.031);
  --secondary-foreground: oklch(0.984 0.003 247.858);

  /* Muted */
  --muted: oklch(0.279 0.041 260.031);
  --muted-foreground: oklch(0.704 0.04 256.788);

  /* Accent */
  --accent: oklch(0.279 0.041 260.031);
  --accent-foreground: oklch(0.984 0.003 247.858);

  /* Destructive — Brighter red for dark */
  --destructive: oklch(0.704 0.191 22.216);
  --destructive-foreground: oklch(0.985 0 0);

  /* Success — Brighter emerald for dark */
  --success: oklch(0.765 0.177 163.223);
  --success-foreground: oklch(0.208 0.042 265.755);

  /* Warning — Brighter amber for dark */
  --warning: oklch(0.828 0.189 84.429);
  --warning-foreground: oklch(0.208 0.042 265.755);

  /* Info — Brighter sky for dark */
  --info: oklch(0.746 0.16 232.661);
  --info-foreground: oklch(0.208 0.042 265.755);

  /* Interactive */
  --border: oklch(1 0 0 / 10%);
  --input: oklch(1 0 0 / 15%);
  --ring: oklch(0.585 0.233 277.117);

  /* Charts — Brighter variants for dark backgrounds */
  --chart-1: oklch(0.673 0.182 276.935);
  --chart-2: oklch(0.765 0.177 163.223);
  --chart-3: oklch(0.828 0.189 84.429);
  --chart-4: oklch(0.712 0.194 13.428);
  --chart-5: oklch(0.714 0.203 305.504);

  /* Sidebar */
  --sidebar: oklch(0.208 0.042 265.755);
  --sidebar-foreground: oklch(0.984 0.003 247.858);
  --sidebar-primary: oklch(0.673 0.182 276.935);
  --sidebar-primary-foreground: oklch(0.984 0.003 247.858);
  --sidebar-accent: oklch(0.279 0.041 260.031);
  --sidebar-accent-foreground: oklch(0.984 0.003 247.858);
  --sidebar-border: oklch(1 0 0 / 10%);
  --sidebar-ring: oklch(0.585 0.233 277.117);
}

@layer base {
  * {
    @apply border-border outline-ring/50;
  }
  body {
    @apply bg-background text-foreground;
  }
}

import type { ClassValue } from 'clsx'
import { clsx } from 'clsx'
import { twMerge } from 'tailwind-merge'

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs))
}

/*
 * JobAutoAgent Tailwind Configuration
 * ──────────────────────────────
 * Design-system tokens for shadcn-vue + OKLCH color scheme.
 * CSS custom-property values are defined in app/assets/css/main.css
 * (light in :root, dark in .dark).
