          DEFAULT: 'var(--warning)',
          foreground: 'var(--warning-foreground)',
        },
        info: {
          DEFAULT: 'var(--info)',
          foreground: 'var(--info-foreground)',
        },

        /* Interactive */
        border: 'var(--border)',
        input: 'var(--input)',
        ring: 'var(--ring)',

        /* Charts */
