 * Chat store — client-only state for message display and streaming.
 *
 * Manages the active conversation buffer, streaming state,
 * and incremental response rendering. Server data (chat history)
 * is owned by TanStack Query — this store only holds ephemeral UI state.
 */
export const useChatStore = defineStore('chat', () => {
  /** Whether the agent is currently streaming a response. */
  const isStreaming = ref(false)

  /** Set streaming state. */
  function setStreaming(streaming: boolean) {
    isStreaming.value = streaming
  }

  return {
    isStreaming,
    setStreaming,
  }
})
