{"content": "/**
 * Nitro server proxy for agent API requests.
 *
 * Proxies all `/api/agent/*` requests to the FastAPI backend,
 * injecting the `X-API-Key` header server-side so the key is
 * never exposed to the browser.
 */
export default defineEventHandler(async (event) => {
  const config = useRuntimeConfig()
  const path = getRouterParam(event, 'path') || ''
  const targetUrl = `${config.public.apiBaseUrl}/api/v1/agent/${path}`

  return proxyRequest(event, targetUrl, {
    headers: {
      'X-API-Key': config.apiKey || '',
    },
  })
})
